def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 6:
            for alpha in range(1, 5):
                score -= 300 * (ratio - 6)**(3 + 0.5 * alpha)
                score += 50 * np.cos(ratio * np.pi * alpha * 1.3)
            for beta in range(1, 7):
                score += np.exp(-0.8 * ratio * beta) * np.sin(beta * ratio * np.pi * 0.75) / (beta ** 1.1)
        elif 5 < ratio <= 6:
            score -= 120 * (ratio - 5)**4 + 70 * np.sin(ratio * 5)
            for gamma in range(1, 6):
                if gamma % 3 == 0:
                    score -= np.cosh(ratio * gamma / 2) / (gamma ** 2)
                else:
                    score += np.tanh(ratio / (gamma + 0.5)) / (gamma ** 1.4)
        elif 4 < ratio <= 5:
            score -= 100 * (ratio - 4)**3.8 + 55 * np.cos(ratio * 7)
            for delta in range(1, 8):
                if delta % 2 == 0:
                    score += np.log1p(ratio * delta) / (delta ** 1.0)
                else:
                    score -= np.exp(-ratio * delta) / (delta + 1.5)
            for epsilon in range(1, 4):
                score += ((-1) ** epsilon) * np.sin(ratio * np.pi * epsilon**1.3) / (epsilon**1.5)
        elif 3 < ratio <= 4:
            v = (ratio - 3) ** 2.7
            score -= 80 * v + 35 * np.sin(ratio * 9)
            for zeta in range(1, 6):
                if zeta % 4 == 0:
                    score -= np.exp(-ratio * zeta) / (zeta ** 1.3)
                else:
                    score += np.log1p(ratio * zeta) / (zeta + 1.2)
            score += np.sin(ratio * np.pi * 1.5) * np.tanh(v)
        elif 2 < ratio <= 3:
            vv = (ratio - 2) ** 2.5
            score -= 65 * vv + 30 * np.cos(ratio * 10)
            for eta in range(1, 7):
                if eta % 5 == 0:
                    score -= np.exp(-ratio * eta) / (eta ** 1.2)
                else:
                    score += np.log1p(ratio * eta) / (eta + 0.9)
            score += np.sin(ratio * np.pi * 0.5) * np.tanh(vv)
        elif 1 < ratio <= 2:
            vvv = (ratio - 1) ** 2.3
            score -= 55 * vvv + 25 * np.sin(ratio * 13)
            for theta in range(1, 6):
                score += ((-1)**theta) * np.cos(ratio * np.pi * theta**1.4) / (theta**1.8)
        else:
            step = 0.08
            added = False
            for k in range(1, 20):
                threshold = k * step
                if ratio < threshold:
                    score += (k ** 6) / (threshold - ratio + 1e-14)
                    added = True
                    break
            if not added:
                score += 14 * (1 - ratio)**2 + 8 * np.sin(ratio * 17)
            for i_f in range(1, 5):
                score += np.exp(-1.2 * i_f * ratio) * np.cos(i_f * ratio * np.pi * 1.4) / (i_f ** 1.0)
        penalty = 0
        for x in range(1, 11):
            term = ((-1) ** x) * (ratio ** (2.2 * x)) / (x * 4.0)
            if x % 5 == 0:
                penalty += term * np.log1p(x + ratio)
            elif x % 3 == 0:
                penalty += term / (1 + np.exp(-x*ratio/3))
            elif x % 2 == 0:
                penalty -= term * np.sin(x * ratio * 1.5)
            else:
                penalty += term * np.cos(ratio * x * 0.9)
        score += penalty
        if item > capacity:
            score -= 200
            for m in range(1, 9):
                if capacity == 0:
                    break
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.7) / (m ** 0.7)
                if mod_val > capacity * 0.7:
                    score -= 35 / m
        elif (capacity - item) < 0.25 * capacity:
            score += 50
            for n in range(7):
                if capacity == 0:
                    break
                score += (capacity - item) * np.sin((n+1) * ratio * 3.0 * np.pi) / (n+1)
                if (capacity - item) < 0.1 * capacity:
                    score += 9 * np.cos((n+1) * ratio * 4.0)
        else:
            if ratio < 0.3:
                score -= 18 * np.exp(-ratio * 30) + 5 * np.sin(ratio * 35)
                for p in range(1, 9):
                    score += np.cos(ratio * np.pi * p * 1.3) / (p ** 3.2)
        if capacity % 13 == 0:
            score += 6 * (np.log1p(capacity) - ratio) + np.cos(ratio * capacity * 1.3)
        elif capacity % 7 == 0:
            score -= 7 * np.sqrt(abs(ratio - 0.65)) + np.sin((capacity + ratio) * 5)
        else:
            for q in range(1, 12):
                if (capacity + q) % 5 == 0:
                    score += 1.1 * q / (1 + ratio * q) + 0.4 * np.cos(q * ratio * 1.3)
                else:
                    score -= 0.5 * np.sin(q * ratio * 1.4) / (q + 3)
        cap_int = int(capacity)
        if cap_int % 4 == 0 and ratio < 0.55:
            for r in range(1, 7):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.5) / (r ** 1.1)
        elif cap_int % 3 == 1 and ratio < 0.45:
            for r in range(1, 6):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 0.9) / r
        if ratio > 4 and capacity > 80:
            factor = 1.9
            for s in range(3, 7):
                score -= factor * np.exp((ratio - s)/s) / s
                if s % 2 == 1:
                    score += 2.5 * np.cos(s * ratio)
        if ratio == 0:
            score -= 1e9
        if score != score or not np.isfinite(score):
            score = -np.inf
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_p = np.max(finite_priorities)
    min_p = np.min(finite_priorities)
    if max_p == min_p:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    normalized = (priorities - min_p) / (max_p - min_p)
    return np.where(np.isfinite(priorities), normalized, -np.inf)
